#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    char s[1005];
    while(T--){
        scanf("%s", s);
        int cnt[26]={0};
        for(int i=0; s[i]; ++i) cnt[s[i]-'a']++;
        int odd=0, pairs=0;
        for(int i=0;i<26;++i){
            if(cnt[i]&1) odd++;
            pairs += cnt[i]/2;
        }
        if(pairs>=odd) puts("YES"); else puts("NO");
    }
    return 0;
}

