const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let pos = 0;
const T = Number(input[pos++]);
let result = [];
for (let tc = 0; tc < T; ++tc) {
  const s = input[pos++];
  const cnt = new Array(26).fill(0);
  for (let i = 0; i < s.length; ++i) cnt[s.charCodeAt(i) - 97]++;
  let odd = 0, pairs = 0;
  for (let i = 0; i < 26; ++i) {
    if (cnt[i] & 1) odd++;
    pairs += cnt[i] >> 1;
  }
  result.push(pairs >= odd ? 'YES' : 'NO');
}
console.log(result.join('\n'));

